func StatusIn(vs ...entmodule.Status) predicate.AiKnowledge {
	v := make([]any, len(vs))
	for i := range v {
		v[i] = vs[i]
	}
	return predicate.AiKnowledge(sql.FieldIn(FieldStatus, v...))
}

// StatusNotIn applies the NotIn predicate on the "status" field.
func StatusNotIn(vs ...entmodule.Status) predicate.AiKnowledge {
	v := make([]any, len(vs))
	for i := range v {
		v[i] = vs[i]
	}
	return predicate.AiKnowledge(sql.FieldNotIn(FieldStatus, v...))
}

// HasAiKnowledgeDocument applies the HasEdge predicate on the "ai_knowledge_document" edge.
func HasAiKnowledgeDocument() predicate.AiKnowledge {
	return predicate.AiKnowledge(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.O2M, false, AiKnowledgeDocumentTable, AiKnowledgeDocumentColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasAiKnowledgeDocumentWith applies the HasEdge predicate on the "ai_knowledge_document" edge with a given conditions (other predicates).
func HasAiKnowledgeDocumentWith(preds ...predicate.AiKnowledgeDocument) predicate.AiKnowledge {
	return predicate.AiKnowledge(func(s *sql.Selector) {
		step := newAiKnowledgeDocumentStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.AiKnowledge) predicate.AiKnowledge {
	return predicate.AiKnowledge(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.AiKnowledge) predicate.AiKnowledge {
	return predicate.AiKnowledge(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.AiKnowledge) predicate.AiKnowledge {
	return predicate.AiKnowledge(sql.NotPredicates(p))
}
